import React, { InputHTMLAttributes } from "react";

import { useStableId } from "../hooks/useStableId.js";
import styles from "./CyberpunkCheckbox.module.css";

export interface CyberpunkCheckboxProps
  extends Omit<InputHTMLAttributes<HTMLInputElement>, "onChange" | "type"> {
  label?: string;
  onChange?: (checked: boolean) => void;
}

export function CyberpunkCheckbox({
  label,
  className = "",
  id,
  onChange,
  ...props
}: CyberpunkCheckboxProps) {
  const inputId = useStableId("checkbox", id);

  return (
    <label htmlFor={inputId} className={`${styles.wrapper} ${className}`.trim()}>
      <input
        id={inputId}
        type="checkbox"
        className={styles.checkbox}
        onChange={(event) => onChange?.(event.target.checked)}
        {...props}
      />
      {label ? <span className={styles.label}>{label}</span> : null}
    </label>
  );
}

.wrapper {
  display: flex;
  align-items: center;
  gap: 0.75rem;
  cursor: pointer;
  user-select: none;
}

.checkbox {
  width: 28px;
  height: 28px;
  border: 2px solid var(--border);
  border-radius: 3px;
  appearance: none;
  outline: none;
  margin: 0;
  cursor: pointer;
  position: relative;
  background-color: var(--bg-primary);
  transition: all var(--transition-fast);
}

.checkbox::before {
  content: "";
  width: 16px;
  height: 16px;
  background-color: var(--success);
  position: absolute;
  top: 4px;
  left: 4px;
  display: block;
  transform: scale(0);
  transition: 120ms transform ease-in-out;
}

.checkbox:checked::before {
  transform: scale(1);
}

.checkbox:hover {
  border-color: var(--success);
}

.checkbox:focus-visible {
  box-shadow: 0 0 0 2px rgba(0, 255, 136, 0.2);
}

.checkbox:disabled {
  opacity: 0.5;
  cursor: not-allowed;
}

.label {
  font-size: 0.875rem;
  color: var(--text-primary);
}

import { useId } from "react";

export function useStableId(prefix: string, explicitId?: string): string {
  const reactId = useId().replace(/:/g, "");
  return explicitId || `${prefix}-${reactId}`;
}
